'use client';

/**
 * Hook for managing commercial procedures (price table)
 */

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { createClient } from '@/lib/supabase/client';
import { useAuth } from '@/hooks/useAuth';
import { useUserProfile } from '@/hooks/useUserProfile';
import { useSecretaryDoctors } from '@/hooks/useSecretaryDoctors';

export const COMMERCIAL_PROCEDURES_KEY = 'commercial-procedures';

interface CommercialProcedure {
    id: string;
    user_id: string;
    name: string;
    description?: string;
    category?: string;
    price: number;
    duration_minutes?: number;
    is_active: boolean;
    created_at: string;
    updated_at?: string;
}

interface CreateProcedureData {
    name: string;
    description?: string;
    category?: string;
    price: number;
    duration_minutes?: number;
    is_active?: boolean;
}

export function useCommercialProcedures(viewAsUserIds?: string[]) {
    const { user } = useAuth();
    const { profile, isSecretaria } = useUserProfile();
    const { doctorIds, isLoading: isLoadingDoctors } = useSecretaryDoctors();
    const queryClient = useQueryClient();

    // Determine which user IDs to fetch for
    const userIds = viewAsUserIds?.length
        ? viewAsUserIds
        : user?.id
            ? isSecretaria && doctorIds?.length
                ? [...doctorIds, user.id]
                : [user.id]
            : [];

    const isAdmin = profile?.role === 'admin' || profile?.role === 'dono';

    const { data: procedures = [], isLoading, error } = useQuery({
        queryKey: [COMMERCIAL_PROCEDURES_KEY, userIds],
        queryFn: async (): Promise<CommercialProcedure[]> => {
            if (!user?.id) return [];

            const supabase = createClient();

            let query = supabase
                .from('commercial_procedures' as any)
                .select('*')
                .order('name', { ascending: true });

            if (!isAdmin && userIds.length > 0) {
                query = query.in('user_id', userIds);
            }

            const { data, error } = await query;

            if (error) {
                console.error('[useCommercialProcedures] Fetch error:', error);
                throw error;
            }

            return (data || []) as CommercialProcedure[];
        },
        enabled: !!user?.id && (!isSecretaria || !isLoadingDoctors),
        staleTime: 5 * 60 * 1000,
    });

    const createProcedure = useMutation({
        mutationFn: async (data: CreateProcedureData) => {
            if (!user?.id) throw new Error('User not authenticated');

            const supabase = createClient();

            const { data: procedure, error } = await supabase
                .from('commercial_procedures' as any)
                .insert({
                    ...data,
                    user_id: user.id,
                    is_active: data.is_active ?? true,
                } as never)
                .select()
                .single();

            if (error) throw error;
            return procedure;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [COMMERCIAL_PROCEDURES_KEY] });
        },
    });

    const updateProcedure = useMutation({
        mutationFn: async ({ id, data }: { id: string; data: Partial<CreateProcedureData> }) => {
            const supabase = createClient();

            const { data: procedure, error } = await supabase
                .from('commercial_procedures' as any)
                .update(data as never)
                .eq('id', id)
                .select()
                .single();

            if (error) throw error;
            return procedure;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [COMMERCIAL_PROCEDURES_KEY] });
        },
    });

    const deleteProcedure = useMutation({
        mutationFn: async (id: string) => {
            const supabase = createClient();

            const { error } = await supabase
                .from('commercial_procedures' as any)
                .delete()
                .eq('id', id);

            if (error) throw error;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: [COMMERCIAL_PROCEDURES_KEY] });
        },
    });

    return {
        procedures,
        isLoading,
        error,
        createProcedure,
        updateProcedure,
        deleteProcedure,
        isCreating: createProcedure.isPending,
        isUpdating: updateProcedure.isPending,
        isDeleting: deleteProcedure.isPending,
    };
}
