'use client';

/**
 * Página de Tabela de Preços / Procedimentos
 */

import { useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Switch } from '@/components/ui/switch';
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter,
} from '@/components/ui/dialog';
import {
    AlertDialog,
    AlertDialogAction,
    AlertDialogCancel,
    AlertDialogContent,
    AlertDialogDescription,
    AlertDialogFooter,
    AlertDialogHeader,
    AlertDialogTitle,
    AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import {
    Plus,
    Search,
    Pencil,
    Trash2,
    Loader2,
    DollarSign,
    Clock,
    Package
} from 'lucide-react';
import { useCommercialProcedures } from '@/hooks/useCommercialProcedures';
import { toast } from '@/hooks/use-toast';
import { Skeleton } from '@/components/ui/skeleton';

const CATEGORIES = [
    'Consulta',
    'Exame',
    'Procedimento',
    'Cirurgia',
    'Tratamento',
    'Retorno',
    'Outro'
];

interface ProcedureFormData {
    name: string;
    description: string;
    category: string;
    price: string;
    duration_minutes: string;
    is_active: boolean;
}

const initialFormData: ProcedureFormData = {
    name: '',
    description: '',
    category: '',
    price: '',
    duration_minutes: '',
    is_active: true,
};

export default function ProceduresPage() {
    const { procedures, isLoading, createProcedure, updateProcedure, deleteProcedure, isCreating, isUpdating, isDeleting } = useCommercialProcedures();
    const [searchTerm, setSearchTerm] = useState('');
    const [filterCategory, setFilterCategory] = useState<string>('all');
    const [showForm, setShowForm] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [formData, setFormData] = useState<ProcedureFormData>(initialFormData);

    const filteredProcedures = procedures.filter(procedure => {
        const matchesSearch = procedure.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
            procedure.description?.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesCategory = filterCategory === 'all' || procedure.category === filterCategory;
        return matchesSearch && matchesCategory;
    });

    const handleOpenForm = (procedure?: any) => {
        if (procedure) {
            setEditingId(procedure.id);
            setFormData({
                name: procedure.name,
                description: procedure.description || '',
                category: procedure.category || '',
                price: procedure.price?.toString() || '',
                duration_minutes: procedure.duration_minutes?.toString() || '',
                is_active: procedure.is_active,
            });
        } else {
            setEditingId(null);
            setFormData(initialFormData);
        }
        setShowForm(true);
    };

    const handleCloseForm = () => {
        setShowForm(false);
        setEditingId(null);
        setFormData(initialFormData);
    };

    const handleSubmit = async () => {
        if (!formData.name || !formData.price) {
            toast({
                title: 'Campos obrigatórios',
                description: 'Nome e preço são obrigatórios.',
                variant: 'destructive',
            });
            return;
        }

        try {
            const data = {
                name: formData.name,
                description: formData.description || undefined,
                category: formData.category || undefined,
                price: parseFloat(formData.price),
                duration_minutes: formData.duration_minutes ? parseInt(formData.duration_minutes) : undefined,
                is_active: formData.is_active,
            };

            if (editingId) {
                await updateProcedure.mutateAsync({ id: editingId, data });
                toast({ title: 'Procedimento atualizado!' });
            } else {
                await createProcedure.mutateAsync(data);
                toast({ title: 'Procedimento criado!' });
            }

            handleCloseForm();
        } catch (error: any) {
            toast({
                title: 'Erro',
                description: error.message || 'Não foi possível salvar o procedimento.',
                variant: 'destructive',
            });
        }
    };

    const handleDelete = async (id: string) => {
        try {
            await deleteProcedure.mutateAsync(id);
            toast({ title: 'Procedimento removido!' });
        } catch (error: any) {
            toast({
                title: 'Erro',
                description: error.message || 'Não foi possível remover o procedimento.',
                variant: 'destructive',
            });
        }
    };

    const formatCurrency = (value: number) => {
        return new Intl.NumberFormat('pt-BR', {
            style: 'currency',
            currency: 'BRL',
        }).format(value);
    };

    if (isLoading) {
        return (
            <div className="min-h-screen space-y-6 bg-background pb-20">
                <Skeleton className="h-12 w-64" />
                <div className="grid gap-4 md:grid-cols-3">
                    {[1, 2, 3].map(i => (
                        <Skeleton key={i} className="h-24" />
                    ))}
                </div>
                <Skeleton className="h-96" />
            </div>
        );
    }

    const totalProcedures = procedures.length;
    const activeProcedures = procedures.filter(p => p.is_active).length;
    const avgPrice = procedures.length > 0
        ? procedures.reduce((sum, p) => sum + p.price, 0) / procedures.length
        : 0;

    return (
        <div className="min-h-screen space-y-6 bg-background pb-20">
            {/* Header */}
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                    <div className="p-3 rounded-xl bg-primary/10">
                        <Package className="h-8 w-8 text-primary" />
                    </div>
                    <div>
                        <h1 className="text-2xl sm:text-3xl font-bold">Tabela de Preços</h1>
                        <p className="text-muted-foreground">Gerencie os procedimentos e valores da sua clínica</p>
                    </div>
                </div>
                <Button onClick={() => handleOpenForm()} className="gap-2">
                    <Plus className="h-4 w-4" />
                    Novo Procedimento
                </Button>
            </div>

            {/* Stats Cards */}
            <div className="grid gap-4 md:grid-cols-3">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Total de Procedimentos</CardTitle>
                        <Package className="h-4 w-4 text-muted-foreground" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{totalProcedures}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Ativos</CardTitle>
                        <Package className="h-4 w-4 text-green-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold text-green-500">{activeProcedures}</div>
                    </CardContent>
                </Card>
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium">Preço Médio</CardTitle>
                        <DollarSign className="h-4 w-4 text-muted-foreground" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{formatCurrency(avgPrice)}</div>
                    </CardContent>
                </Card>
            </div>

            {/* Filters */}
            <Card>
                <CardContent className="pt-6">
                    <div className="flex flex-col sm:flex-row gap-4">
                        <div className="flex-1 relative">
                            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Buscar procedimentos..."
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="pl-10"
                            />
                        </div>
                        <Select value={filterCategory} onValueChange={setFilterCategory}>
                            <SelectTrigger className="w-full sm:w-48">
                                <SelectValue placeholder="Filtrar por categoria" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">Todas categorias</SelectItem>
                                {CATEGORIES.map(cat => (
                                    <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>
                    </div>
                </CardContent>
            </Card>

            {/* Table */}
            <Card>
                <CardHeader>
                    <CardTitle>Procedimentos</CardTitle>
                    <CardDescription>
                        {filteredProcedures.length} procedimento(s) encontrado(s)
                    </CardDescription>
                </CardHeader>
                <CardContent>
                    {filteredProcedures.length === 0 ? (
                        <div className="text-center py-10 text-muted-foreground">
                            Nenhum procedimento encontrado.
                        </div>
                    ) : (
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Procedimento</TableHead>
                                    <TableHead>Categoria</TableHead>
                                    <TableHead>Duração</TableHead>
                                    <TableHead>Preço</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="text-right">Ações</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {filteredProcedures.map((procedure) => (
                                    <TableRow key={procedure.id}>
                                        <TableCell>
                                            <div>
                                                <p className="font-medium">{procedure.name}</p>
                                                {procedure.description && (
                                                    <p className="text-sm text-muted-foreground line-clamp-1">
                                                        {procedure.description}
                                                    </p>
                                                )}
                                            </div>
                                        </TableCell>
                                        <TableCell>
                                            {procedure.category && (
                                                <Badge variant="outline">{procedure.category}</Badge>
                                            )}
                                        </TableCell>
                                        <TableCell>
                                            {procedure.duration_minutes ? (
                                                <div className="flex items-center gap-1 text-muted-foreground">
                                                    <Clock className="h-3 w-3" />
                                                    {procedure.duration_minutes} min
                                                </div>
                                            ) : (
                                                '-'
                                            )}
                                        </TableCell>
                                        <TableCell className="font-medium">
                                            {formatCurrency(procedure.price)}
                                        </TableCell>
                                        <TableCell>
                                            <Badge variant={procedure.is_active ? 'default' : 'secondary'}>
                                                {procedure.is_active ? 'Ativo' : 'Inativo'}
                                            </Badge>
                                        </TableCell>
                                        <TableCell className="text-right">
                                            <div className="flex justify-end gap-2">
                                                <Button
                                                    size="icon"
                                                    variant="ghost"
                                                    onClick={() => handleOpenForm(procedure)}
                                                >
                                                    <Pencil className="h-4 w-4" />
                                                </Button>
                                                <AlertDialog>
                                                    <AlertDialogTrigger asChild>
                                                        <Button size="icon" variant="ghost">
                                                            <Trash2 className="h-4 w-4" />
                                                        </Button>
                                                    </AlertDialogTrigger>
                                                    <AlertDialogContent>
                                                        <AlertDialogHeader>
                                                            <AlertDialogTitle>Excluir Procedimento?</AlertDialogTitle>
                                                            <AlertDialogDescription>
                                                                Esta ação não pode ser desfeita. O procedimento será permanentemente removido.
                                                            </AlertDialogDescription>
                                                        </AlertDialogHeader>
                                                        <AlertDialogFooter>
                                                            <AlertDialogCancel>Cancelar</AlertDialogCancel>
                                                            <AlertDialogAction
                                                                onClick={() => handleDelete(procedure.id)}
                                                                disabled={isDeleting}
                                                            >
                                                                Excluir
                                                            </AlertDialogAction>
                                                        </AlertDialogFooter>
                                                    </AlertDialogContent>
                                                </AlertDialog>
                                            </div>
                                        </TableCell>
                                    </TableRow>
                                ))}
                            </TableBody>
                        </Table>
                    )}
                </CardContent>
            </Card>

            {/* Form Dialog */}
            <Dialog open={showForm} onOpenChange={setShowForm}>
                <DialogContent className="max-w-md">
                    <DialogHeader>
                        <DialogTitle>
                            {editingId ? 'Editar Procedimento' : 'Novo Procedimento'}
                        </DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        <div className="space-y-2">
                            <Label htmlFor="name">Nome *</Label>
                            <Input
                                id="name"
                                value={formData.name}
                                onChange={(e) => setFormData(prev => ({ ...prev, name: e.target.value }))}
                                placeholder="Ex: Consulta de Rotina"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="description">Descrição</Label>
                            <Textarea
                                id="description"
                                value={formData.description}
                                onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                placeholder="Descrição do procedimento..."
                                rows={3}
                            />
                        </div>
                        <div className="space-y-2">
                            <Label htmlFor="category">Categoria</Label>
                            <Select
                                value={formData.category}
                                onValueChange={(value) => setFormData(prev => ({ ...prev, category: value }))}
                            >
                                <SelectTrigger>
                                    <SelectValue placeholder="Selecione uma categoria" />
                                </SelectTrigger>
                                <SelectContent>
                                    {CATEGORIES.map(cat => (
                                        <SelectItem key={cat} value={cat}>{cat}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                            <div className="space-y-2">
                                <Label htmlFor="price">Preço (R$) *</Label>
                                <Input
                                    id="price"
                                    type="number"
                                    step="0.01"
                                    min="0"
                                    value={formData.price}
                                    onChange={(e) => setFormData(prev => ({ ...prev, price: e.target.value }))}
                                    placeholder="0,00"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label htmlFor="duration">Duração (min)</Label>
                                <Input
                                    id="duration"
                                    type="number"
                                    min="0"
                                    value={formData.duration_minutes}
                                    onChange={(e) => setFormData(prev => ({ ...prev, duration_minutes: e.target.value }))}
                                    placeholder="30"
                                />
                            </div>
                        </div>
                        <div className="flex items-center justify-between">
                            <div className="space-y-0.5">
                                <Label>Ativo</Label>
                                <p className="text-sm text-muted-foreground">
                                    Procedimentos inativos não aparecem para seleção
                                </p>
                            </div>
                            <Switch
                                checked={formData.is_active}
                                onCheckedChange={(checked) => setFormData(prev => ({ ...prev, is_active: checked }))}
                            />
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={handleCloseForm}>
                            Cancelar
                        </Button>
                        <Button onClick={handleSubmit} disabled={isCreating || isUpdating}>
                            {(isCreating || isUpdating) && <Loader2 className="h-4 w-4 mr-2 animate-spin" />}
                            {editingId ? 'Salvar' : 'Criar'}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    );
}
